cd "G:\AI\telegram-kiro-bridge-main" && cat > /tmp/test-redact.mjs << 'EOF'
import { redactArgs } from "./dist/tool-observer.js";

// Vector 1: nested object {env:{API_KEY:"sk-secret"}}
const v1 = redactArgs({ env: { API_KEY: "sk-secret" } });
console.log("V1 nested env:", JSON.stringify(v1));

// Vector 2a: non-command string value with secret
const v2a = redactArgs({ script: "export TOKEN=sk-abc" });
console.log("V2a script string:", JSON.stringify(v2a));

// Vector 2b: array value with token
const v2b = redactArgs({ args_list: ["--token", "sk-xyz"] });
console.log("V2b array:", JSON.stringify(v2b));

// Vector 3: command with postgres URL embedding password
const v3 = redactArgs({ command: "psql postgres://user:pass@host/db" });
console.log("V3 pg url:", JSON.stringify(v3));

// Control: top-level secret key works
const c1 = redactArgs({ api_key: "sk-top", normal: "value" });
console.log("Control top-level key:", JSON.stringify(c1));

// Control: command -p flag and Bearer
const c2 = redactArgs({ command: "curl -H 'Authorization: Bearer sk-123' && mysql -psecret" });
console.log("Control command scrub:", JSON.stringify(c2));
EOF
node /tmp/test-redact.mjs

